mapper.select:
SELECT a.id, a.`key`, a.`value`, a.type, a.object_id objectId, a.object_key objectKey, a.environment_id environmentId, a.remark, a.create_id createId, CONVERT(a.create_time, char) createTime, a.last_update_id lastUpdateId, CONVERT(a.last_update_time, char) lastUpdateTime FROM auto_variable a
AND a.tenant_id = #{tenantId}
AND a.object_id = #{objectId}
AND a.object_key = #{objectKey}
AND a.type = #{type}
${sqlExtract}
ORDER BY a.create_time DESC
